fn codex_catalog_model_entry(
    template: &Value,
    spec: &CodexCatalogModelSpec,
    priority: usize,
    profile: CodexCatalogToolProfile,
) -> Value {
    let mut entry = template.clone();
    let Some(entry_obj) = entry.as_object_mut() else {
        return json!({});
    };

    // Override basic fields
    entry_obj.insert("slug".to_string(), json!(spec.model));
    entry_obj.insert("display_name".to_string(), json!(spec.display_name));
    entry_obj.insert("description".to_string(), json!(spec.display_name));
    entry_obj.insert("context_window".to_string(), json!(spec.context_window));
    entry_obj.insert("max_context_window".to_string(), json!(spec.context_window));
    entry_obj.insert("priority".to_string(), json!(1000 + priority));
    entry_obj.insert("additional_speed_tiers".to_string(), json!([]));
    entry_obj.insert("service_tiers".to_string(), json!([]));
    entry_obj.insert("availability_nux".to_string(), Value::Null);
    entry_obj.insert("upgrade".to_string(), Value::Null);

    // Reasoning levels
    entry_obj.insert("default_reasoning_level".to_string(), json!("low"));
    entry_obj.insert("supported_reasoning_levels".to_string(), json!([...]));

    // Service tiers
    entry_obj.insert("service_tiers".to_string(), json!([...]));

    // Image support
    entry_obj.insert(
        "input_modalities".to_string(),
        json!(codex_catalog_input_modalities(...)),
    );

    // Non-ProxyChat: strip OpenAI-specific keys
    if profile != CodexCatalogToolProfile::ProxyChat {
        for key in [
            "apply_patch_tool_type",
            "web_search_tool_type",
            "tools",
            "model_messages",
        ] {
            entry_obj.remove(key);
        }
        entry_obj.insert("shell_type".to_string(), json!("shell_command"));

        if let Some(base_instructions) = spec.base_instructions.as_deref().map(str::trim).filter(|s| !s.is_empty()) {
            entry_obj.insert("base_instructions".to_string(), json!(base_instructions));
        }
        if let Some(parallel) = spec.supports_parallel_tool_calls {
            entry_obj.insert("supports_parallel_tool_calls".to_string(), json!(parallel));
        }
    }

    // NEW CHANGE (lines ~540-546):
    // ProxyChat providers inherit the template's use_responses_lite,
    // which may be true for OpenAI models. Force false for third-party.
    if profile == CodexCatalogToolProfile::ProxyChat {
        entry_obj.insert("use_responses_lite".to_string(), json!(false));
    }

    entry
}
```

